/**
 * MMS Project - Agent Configuration
 * Enforces state machine architecture over React hooks
 */

import type { AgentConfig, AgentHookContext } from "@belt/ai";

const REACT_HOOKS_PATTERN =
  /(useState|useEffect|useReducer|useContext|useCallback|useMemo|useLayoutEffect|useImperativeHandle|useDebugValue|useTransition|useDeferredValue)\s*\(/;

const config: AgentConfig = {
  hooks: {
    PreToolUse: async (ctx: AgentHookContext) => {
      const { tool, input, filePath } = ctx;

      // Block git commits with Co-Authored-By
      if (tool === "Bash") {
        const command = input.command as string | undefined;

        if (command && /git\s+commit/.test(command)) {
          if (/Co-Authored-By/i.test(command)) {
            ctx.block(
              "Commits with Co-Authored-By are not allowed.\n\n" +
                "WHY: This project requires clean commit authorship.\n" +
                "FIX: Remove the Co-Authored-By line from your commit message.",
            );
          }
        }
      }

      // Only check Write/Edit operations
      if (tool !== "Write" && tool !== "Edit") {
        return;
      }

      // Only check TypeScript/JavaScript files
      if (!/\.(tsx?|jsx?)$/.test(filePath)) {
        return;
      }

      // Skip test files
      if (/\.(test|spec)\.(tsx?|jsx?)$/.test(filePath)) {
        return;
      }

      // Extract content to be written
      const content = (input.content || input.new_string) as string | undefined;
      if (!content) {
        return;
      }

      // Check for React hooks (excluding useRef)
      if (REACT_HOOKS_PATTERN.test(content)) {
        ctx.block(
          "React hooks detected (useState, useEffect, etc).\n\n" +
            "WHY: Hooks create SCATTERED state (not traceable, no action history).\n" +
            "USE: @belt/tools for CENTRALIZED state (machine.getState() shows everything).\n\n" +
            "Example:\n" +
            "  ❌ const [x, setX] = useState(0)\n" +
            '  ✅ const { state } = machine.useMachine("slice")\n\n' +
            "See CLAUDE.md for state machine patterns.",
        );
      }
    },
  },
};

export default config;

# MMS Demo Application

**Metro Fleet Mileage Management System** - Win-the-bid demonstration application.

## Overview

This is a demonstration application for Metro fleet preventive maintenance (PM) management. It showcases CSV-based PM projection over a 10-year horizon with an infinite canvas interface using semantic zoom levels (strategic → tactical → operational views).

**Key Features:**
- Drag-and-drop PM rescheduling with constraint validation
- "Bow-wave" risk visualization (fleet maintenance clustering)
- WebGL-powered infinite canvas rendering with deck.gl
- State management with @belt/tools

## Getting Started

```bash
# Install dependencies
bun install

# Start development server
bun dev

# Build for production
bun run build

# Lint code
bun run lint

# Format code
bun run format
```

## Project Structure

```
src/
├── main.tsx              # Entry point
├── App.tsx               # Root component
├── store/                # @belt/tools state machines
├── engine/               # PM projection algorithm (CRITICAL)
├── import/               # CSV parsing and validation
├── canvas/               # deck.gl infinite canvas
├── components/           # React UI components
├── types/                # TypeScript interfaces
└── utils/                # Helpers

public/sample-data/       # Sample CSV files for testing
docs/                     # 9-part specification (MMS_SPEC_001-009)
```

